INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (26232022, 0, 21, "", 26232, "", "vo_wac_221103_201", "", "", "vo_wac_221103", 0);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (26232023, 10, 11, 0, 26232, 0, "そんなことない！　バッチリだよ！\nやっぱりグレアは天才かも！\nアートの申し子で間違いない！\nルゥもそう思うでしょ！", 1, 0.5, 109211, 1);
INSERT INTO `v1_e0f9eab49b1549c1e3fe953547aaf5a5aa76613a2a3c6afda5525b62389b1dae` VALUES (26232024, "", 91, "", 26232, "", "", "", "", 0, "");
